BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?name ?type WHERE {
  <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::01%2520Components::Operational::APS::Conceptual%2520Design::APS%2520Conceptual> vocab:Element_ownedElement ?elem .
  ?elem rdf:type ?type .
  OPTIONAL { ?elem vocab:NamedElement_name ?name }
  FILTER(?type IN (vocab:block, vocab:part%20property))
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?name ?type WHERE {
  ?elem vocab:NamedElement_qualifiedName ?qname .
  FILTER(CONTAINS(LCASE(STR(?qname)), LCASE("Alignment and Phasing System")))
  OPTIONAL { ?elem vocab:NamedElement_name ?name }
  ?elem rdf:type ?type .
}
LIMIT 10

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?name ?type WHERE {
  ?elem vocab:NamedElement_qualifiedName ?qname .
  FILTER(CONTAINS(LCASE(STR(?qname)), LCASE("alignment%20and%20phasing")))
  OPTIONAL { ?elem vocab:NamedElement_name ?name }
  ?elem rdf:type ?type .
}
LIMIT 10

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?name ?description WHERE {
  ?elem rdf:type vocab:block .
  ?elem vocab:NamedElement_name ?name .
  FILTER(CONTAINS(LCASE(STR(?name)), LCASE("APS")))
  OPTIONAL { ?elem vocab:Comment_body ?description }
}
LIMIT 10
